class Solution {
    public int clumsy(int n) {
        if (n <= 2) return n;
        if (n == 3) return 3;

        int result = n;
        n -= 1;
        boolean isMultiply = true;
        while (n > 0) {
            if (isMultiply) {
                result *= n;
                isMultiply = false;
            } else if (n > 1) {
                result /= n;
                n -= 1;
                isMultiply = true;
            } else {
                result += n;
                n -= 1;
                isMultiply = true;
            }
            n -= 1;
        }
        if (result < 0) {
            result = 0;
        }
        return result;
    }
}
```
