class Solution {
    public int clumsy(int n) {
        if (n <= 2) return n;
        if (n == 3) return 3;

        int result = n * (n - 1) / (n - 2);
        n = n - 3;
        boolean add = true;
        while (n > 0) {
            if (add) {
                result += n;
            } else {
                result -= n;
            }
            add = !add;
            n -= 1;
        }
        return result;
    }
}
